128	func (f *CommandFactory) runAgentExecuteLoopImpl(cmd *cobra.Command, treatPassthroughAsOpaque bool, tryTargetBeadID string) error {
129		spec, dispatch, err := parseExecuteLoopSpec(cmd, treatPassthroughAsOpaque)
130		if err != nil {
131			return err
132		}
133		projectRoot := resolveProjectRoot(spec.ProjectRoot, f.WorkingDir)
134		spec.ProjectRoot = projectRoot
135		if tryTargetBeadID != "" {
136			spec.Mode = executeloop.ModeOnce
137			spec.IdleInterval = executeloop.Duration{}
138		}
139	
140		noRoutingFlags := spec.Harness == "" && spec.Model == "" && spec.Provider == "" &&
141			spec.Profile == "" && spec.MinPower == 0 &&
142			spec.MaxPower == 0 && !cmd.Flags().Changed("harness") &&
143			!cmd.Flags().Changed("model") && !cmd.Flags().Changed("provider") &&
144			!cmd.Flags().Changed("profile") &&
145			!cmd.Flags().Changed("min-power") && !cmd.Flags().Changed("max-power")
146		autoInferTier := noRoutingFlags && !projectHasRoutingConfig(projectRoot)
147	
148		if !spec.OpaquePassthrough {
149			if err := agent.ValidateForExecuteLoopViaService(cmd.Context(), f.WorkingDir, spec.Harness, spec.Model, spec.Provider); err != nil {
150				return fmt.Errorf("execute-loop: %w", err)
151			}
152		}
153	
154		store := bead.NewStore(filepath.Join(projectRoot, ".ddx"))
155	
156		loopSessionID := fmt.Sprintf("agent-loop-%d", time.Now().UnixNano())
157		loopLogDir := filepath.Join(projectRoot, agent.DefaultLogDir)
158		_ = os.MkdirAll(loopLogDir, 0o755)
159		loopLogPath := filepath.Join(loopLogDir, loopSessionID+".jsonl")
160		var loopSink io.Writer
161		if lf, err := os.OpenFile(loopLogPath, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o644); err == nil {
162			loopSink = lf
163			defer lf.Close() //nolint:errcheck
164		}
165	
166		probeIdent := workerprobe.Identity{
167			ProjectRoot:  projectRoot,
168			Harness:      spec.Harness,
169			Model:        spec.Model,
170			ExecutorPID:  os.Getpid(),
171			ExecutorHost: hostnameOrEmpty(),
172			StartedAt:    time.Now().UTC(),
173		}
174		probe := workerprobe.New(probeIdent, workerprobe.Config{AddrFunc: serverpkg.ReadServerAddr})
175		probeCtx, probeCancel := context.WithCancel(context.Background())
176		probe.Start(probeCtx)
177		defer func() {
178			probeCancel()
179			probe.Stop()
180		}()
181		if loopSink != nil {
182			loopSink = workerprobe.TeeJSONL(loopSink, probe)
183		} else {
184			loopSink = workerprobe.TeeJSONL(io.Discard, probe)
185		}
186	
187		localCoord := serverpkg.NewLocalLandCoordinator(projectRoot, agent.RealLandingGitOps{})
188		defer localCoord.Stop()
189	
190		var reviewer agent.BeadReviewer
191		if !spec.NoReview {
192			reviewer = &agent.DefaultBeadReviewer{
193				ProjectRoot: projectRoot,
194				BeadStore:   bead.NewStore(filepath.Join(projectRoot, ".ddx")),
195				BeadEvents:  bead.NewStore(filepath.Join(projectRoot, ".ddx")),
196				Harness:     spec.ReviewHarness,
197				Model:       spec.ReviewModel,
198			}
199		}
200	
201		spec.Profile = agent.NormalizeRoutingProfile(spec.Profile)
202	
203		overrides := config.CLIOverrides{
204			Assignee:          resolveClaimAssignee(),
205			Harness:           spec.Harness,
206			Model:             spec.Model,
207			Provider:          spec.Provider,
208			Profile:           spec.Profile,
209			Effort:            spec.Effort,
210			MinPower:          spec.MinPower,
211			MaxPower:          spec.MaxPower,
212			OpaquePassthrough: spec.OpaquePassthrough,
213		}
214		rcfg, err := config.LoadAndResolve(projectRoot, overrides)
215		if err != nil {
216			return fmt.Errorf("load resolved config: %w", err)
217		}
218	
219		resourceChecker := buildCLIResourceChecker(projectRoot, f.resourceCheckerOverride)
220		if _, err := resourceChecker.Check(cmd.Context()); err != nil {
221			var resourceErr *agent.ResourceExhaustedError
222			if errors.As(err, &resourceErr) {
223				_, _ = fmt.Fprintln(cmd.OutOrStdout(), agent.ResourceExhaustedStopMessage)
224			}
225			return err
226		}
227	
228		var qualityRunner agent.AgentRunner
229		if f.AgentRunnerOverride != nil {
230			qualityRunner = f.AgentRunnerOverride
231		}
232		lintHook := agent.NewPreDispatchLintHook(projectRoot, store, rcfg, nil, qualityRunner)
233		innerIntakeHook := agent.NewPreClaimIntakeHook(projectRoot, store, rcfg, nil, qualityRunner)
234		intakeHook := agent.NewACQualityPreClaimGate(store, rcfg.BeadQualityMode(), rcfg.ACQualityMinScore(), innerIntakeHook)
235		triageHook := agent.NewPostAttemptTriageHook(projectRoot, store, rcfg, nil, qualityRunner, nil)
236		decompositionHook := agent.NewPreClaimDecompositionHook(store, qualityRunner, rcfg, projectRoot)
237		recoveryHook := agent.NewAutoRecoveryPostLadderExhaustionHook(store, qualityRunner, rcfg, projectRoot, agent.AutoRecoveryConfig{
238			MaxRecoveryCostUSD: spec.MaxRecoveryCostUSD,
239			MaxBeadCostUSD:     spec.MaxBeadCostUSD,
240		})
241	
242		harnessBilledLookup := func(harnessName string) bool {
243			svc, svcErr := agent.NewServiceFromWorkDir(f.WorkingDir)
244			if svcErr != nil {
245				return true
246			}
247			infos, err := svc.ListHarnesses(context.Background())
248			if err != nil {
249				return true
250			}
251			for _, h := range infos {
252				if h.Name == harnessName {
253					return escalation.CountsTowardCostCap(h.CostClass == "local", h.Billing == agentlib.BillingModelSubscription, h.CostClass)
254				}
255			}
256			return true
257		}
258	
259		costCap := escalation.NewCostCapTracker(spec.MaxCostUSD, harnessBilledLookup)
260		profileSelector := newImplementationProfileSelector(projectRoot)
261		accumulateBilledCost := func(report agent.ExecuteBeadReport) {
262			costCap.Add(report.Harness, report.CostUSD)
263		}
264		costCapTripped := func() (work.StopDecision, agent.ExecuteBeadReport, bool) {
265			if _, tripped := costCap.Tripped(); !tripped {
266				return work.StopDecision{}, agent.ExecuteBeadReport{}, false
267			}
268			spent := costCap.Spent()
269			decision, _ := work.ClassifyStop(work.StopInput{Budget: true})
270			return decision, agent.ExecuteBeadReport{
271				Status: agent.ExecuteBeadStatusExecutionFailed,
272				Detail: fmt.Sprintf("cost cap reached: $%.2f billed >= $%.2f cap; raise the cap or set 0 to disable. Subscription and local providers do not count.", spent, spec.MaxCostUSD),
273			}, true
274		}
275	
276		singleTierAttempt := func(ctx context.Context, beadID string, requestedMinPower int, requestedProfile string, requestedTier escalation.ModelTier, routingNote string, resolvedHarness, resolvedProvider, resolvedModel string) (agent.ExecuteBeadReport, error) {
277			gitOps := &agent.RealGitOps{}
278			attemptProvider := spec.Provider
279			if resolvedProvider != "" {
280				attemptProvider = resolvedProvider
281			}
282			reportFromResult := func(res *agent.ExecuteBeadResult) agent.ExecuteBeadReport {
283				report := agent.ReportFromExecuteBeadResult(res, string(requestedTier))
284				report.RequestedTier = string(requestedTier)
285				report.RequestedProfile = requestedProfile
286				report.RoutingIntentNote = routingNote
287				return report
288			}
289			loopOverrides := config.CLIOverrides{
290				Harness:           resolvedHarness,
291				Model:             resolvedModel,
292				Provider:          attemptProvider,
293				Profile:           requestedProfile,
294				Effort:            spec.Effort,
295				MinPower:          requestedMinPower,
296				MaxPower:          spec.MaxPower,
297				OpaquePassthrough: spec.OpaquePassthrough,
298			}
299			requestTimeout := spec.RequestTimeout.Duration
300			if requestTimeout > 0 {
301				loopOverrides.ProviderRequestTimeout = &requestTimeout
302			}
303			attemptRcfg, _ := config.LoadAndResolve(projectRoot, loopOverrides)
304			res, execErr := agent.ExecuteBeadWithConfig(ctx, projectRoot, beadID, attemptRcfg, executeLoopAttemptRuntime(
305				spec,
306				cmd.OutOrStdout(),
307				bead.NewStore(filepath.Join(projectRoot, ".ddx")),
308				f.AgentRunnerOverride,
309				resourceChecker,
310			), gitOps)
311			if execErr != nil && res == nil {
312				return agent.ExecuteBeadReport{}, execErr
313			}
314			if res != nil && agent.IsResourceExhaustedStatus(res.Status) {
315				return reportFromResult(res), nil
316			}
317			if execErr != nil {
318				agent.MarkResultExecutionError(res, execErr)
319				return reportFromResult(res), nil
320			}
321			if res != nil && res.ResultRev != "" && res.ResultRev != res.BaseRev && res.ExitCode == 0 {
322				targetBead, _ := store.Get(context.Background(), beadID)
323				landRes, _, landErr := agent.SubmitWithPreMergeChecks(
324					ctx, projectRoot, targetBead, res,
325					func(req agent.LandRequest) (*agent.LandResult, error) { return localCoord.Submit(req) },
326					bead.NewStore(filepath.Join(projectRoot, ".ddx")),
327					resolveClaimAssignee(), "ddx work",
328					nil,
329				)
330				if landErr == nil {
331					agent.ApplyLandResultToExecuteBeadResult(res, landRes)
332					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
333				} else {
334					agent.MarkResultLandError(projectRoot, res, landErr)
335					_ = agent.WriteExecuteBeadResultArtifact(projectRoot, res)
336					return reportFromResult(res), nil
337				}
338			} else if res != nil && (res.Outcome == agent.ExecuteBeadOutcomeTaskFailed || res.ExitCode != 0) {
339				if res.ResultRev != "" && res.ResultRev != res.BaseRev {
340					res.Outcome = "preserved"
341				} else {
342					res.Outcome = "error"
343				}
344				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
345			} else if res != nil && res.ResultRev == res.BaseRev {
346				res.Outcome = "no-changes"
347				res.Status = agent.ClassifyExecuteBeadStatus(res.Outcome, res.ExitCode, res.Reason)
348			}
349			return reportFromResult(res), nil
350		}
351	
352		var ladderOnce sync.Once
353		var ladder escalationFloorFinder
354		loadLadder := func() escalationFloorFinder {
355			ladderOnce.Do(func() {
356				ladder = tierescalation.NewLadder(nil)
357				svc, svcErr := agent.ResolveServiceFromWorkDir(projectRoot)
358				if svcErr != nil {
359					return
360				}
361				modelFilter := agentlib.ModelFilter{}
362				if spec.Harness != "" {
363					modelFilter.Harness = spec.Harness
364				}
365				modelCtx, cancel := context.WithTimeout(cmd.Context(), 2*time.Second)
366				defer cancel()
367				models, listErr := svc.ListModels(modelCtx, modelFilter)
368				if listErr != nil {
369					return
370				}
371				ladder = tierescalation.NewLadder(models)
372			})
373			return ladder
374		}
375	
376		worker := &agent.ExecuteBeadWorker{
377			Store:    store,
378			Reviewer: reviewer,
379			EscalationNextFloor: func(actualPower int) (int, error) {
380				return nextEscalationFloor(loadLadder(), actualPower)
381			},
382			Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
383				targetBead, err := store.Get(context.Background(), beadID)
384				if err != nil {
385					return agent.ExecuteBeadReport{}, err
386				}
387				inferredTier := escalation.ModelTier("")
388				if autoInferTier {
389					inferredTier = escalation.InferTier(targetBead)
390				}
391				initialMinPower, unavailableReport, unavailable := investigationRetryInitialMinPowerWithInference(targetBead, rcfg.MinPower(), spec.MaxPower, loadLadder(), false)
392				if unavailable {
393					return unavailableReport, nil
394				}
395				initialProfile := spec.Profile
396				initialRoutingNote := ""
397				if autoInferTier {
398					if selection, selectErr := profileSelector.Select(ctx, inferredTier, initialMinPower); selectErr == nil && selection.Name != "" {
399						initialProfile = selection.Name
400						initialRoutingNote = selection.Note
401						if spec.MaxPower > 0 && initialMinPower > 0 && initialMinPower >= spec.MaxPower {
402							unavailableReport := smartRouteUnavailableReport(targetBead, initialMinPower, spec.MaxPower, nil)
403							unavailableReport.RequestedTier = string(inferredTier)
404							unavailableReport.RequestedProfile = initialProfile
405							unavailableReport.RoutingIntentNote = initialRoutingNote
406							return unavailableReport, nil
407						}
408					} else {
409						initialMinPower, unavailableReport, unavailable = zeroConfigInferredMinPower(targetBead, initialMinPower, spec.MaxPower, loadLadder())
410						if unavailable {
411							unavailableReport.RequestedTier = string(inferredTier)
412							return unavailableReport, nil
413						}
414					}
415				}
416				perBeadBudget := spec.MaxBeadCostUSD
417				if override, ok := escalation.ParseBeadBudgetLabel(targetBead.Labels); ok {
418					perBeadBudget = override
419				}
420				perBeadTracker := escalation.NewPerBeadCostTracker(perBeadBudget, harnessBilledLookup)
421				report, err := runEscalatingSingleTierAttempts(
422					ctx,
423					initialMinPower,
424					loadLadder(),
425					func(ctx context.Context, requestedMinPower int) (agent.ExecuteBeadReport, error) {
426						requestProfile := initialProfile
427						routingNote := initialRoutingNote
428						if autoInferTier {
429							if selection, selectErr := profileSelector.Select(ctx, inferredTier, requestedMinPower); selectErr == nil {
430								// Empty selection means no no-extra-requirement policy covers this
431								// retry floor. Drop the stale lower policy and send MinPower-only so
432								// Fizeau can route or report no eligible candidate from live config.
433								requestProfile = selection.Name
434								if requestProfile == "" {
435									routingNote = ""
436								} else if selection.Note != "" {
437									routingNote = selection.Note
438								}
439							}
440						}
441						return singleTierAttempt(ctx, beadID, requestedMinPower, requestProfile, inferredTier, routingNote, spec.Harness, spec.Provider, spec.Model)
442					},
443					nil,
444					perBeadTracker,
445				)
446				if err == nil {
447					accumulateBilledCost(report)
448				}
449				return report, err
450			}),
451		}
452	
453		cliLandingOps := agent.RealLandingGitOps{}
454		progressLog := cmd.OutOrStdout()
455		cleanupLog := cmd.ErrOrStderr()
456		jsonOutput := dispatch.JSON == "true"
457		if jsonOutput {
458			progressLog = io.Discard
459			cleanupLog = io.Discard
460		}
461		result, err := worker.Run(cmd.Context(), rcfg, agent.ExecuteBeadLoopRuntime{
462			Mode:                         spec.Mode,
463			IdleInterval:                 spec.IdleInterval.Duration,
464			Log:                          progressLog,
465			CleanupLog:                   cleanupLog,
466			EventSink:                    loopSink,
467			WorkerID:                     resolveClaimAssignee(),
468			ProjectRoot:                  projectRoot,
469			CleanupRunner:                agent.NewExecutionCleanupManager(projectRoot, &agent.RealGitOps{}),
470			ResourceChecker:              resourceChecker,
471			BinaryRefreshCheck:           f.buildWorkBinaryRefreshCheck(cmd, projectRoot, tryTargetBeadID),
472			SessionID:                    loopSessionID,
473			PreClaimHook:                 buildCLIPreClaimHook(projectRoot, cliLandingOps),
474			PreClaimIntakeHook:           intakeHook,
475			PreClaimTimeout:              spec.PreClaimTimeout.Duration,
476			PreDispatchLintHook:          lintHook,
477			PostAttemptTriageHook:        triageHook,
478			PostAttemptDecompositionHook: decompositionHook,
479			BudgetStop:                   costCapTripped,
480			NoReview:                     spec.NoReview,
481			TargetBeadID:                 tryTargetBeadID,
482			ReviewCostCap:                costCap,
483			OnAttemptFinalized:           buildAttemptMetricsHook(projectRoot, store, spec.Profile),
484			PostLadderExhaustionHook:     recoveryHook,
485		})
486		if err != nil && result != nil && (errors.Is(err, context.Canceled) || errors.Is(err, context.DeadlineExceeded)) {
487			_ = writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
488		}
489		if err != nil {
490			return err
491		}
492		if result != nil && result.ExitReason == "binary_refresh" {
493			return nil
494		}
495		return writeExecuteLoopResult(cmd.OutOrStdout(), projectRoot, result, jsonOutput)
496	}
