1	package escalation
2	
3	import (
4		"fmt"
5		"strings"
6	
7		"github.com/DocumentDrivenDX/ddx/internal/bead"
8	)
9	
10	const triageTierHintKey = "triage.tier_hint"
11	
12	// InferTier returns a recommended ModelTier for a bead based on its metadata.
13	// It inspects, in priority order: an explicit "tier:" label, the kind/priority
14	// labels and IssueType, then falls back to an estimated-scope heuristic on the
15	// description length.
16	//
17	// The default for a bead with no useful signal is TierCheap, matching the
18	// hot-fix behavior in cmd/agent_cmd.go runAgentExecuteLoopImpl that this
19	// engine replaces. Aligns with the endpoint-first routing redesign goal of
20	// cheap-by-default with metadata-driven escalation.
21	func InferTier(b *bead.Bead) ModelTier {
22		if b == nil {
23			return TierCheap
24		}
25		if tier, ok := triageTierHint(b); ok {
26			return tier
27		}
28	
29		kindLabel := ""
30		priorityLabel := ""
31		for _, raw := range b.Labels {
32			l := strings.ToLower(strings.TrimSpace(raw))
33			if l == "" {
34				continue
35			}
36			// Explicit override wins.
37			if tier, ok := parseTierLabel(l); ok {
38				return tier
39			}
40			if v, ok := strings.CutPrefix(l, "kind:"); ok {
41				kindLabel = strings.TrimSpace(v)
42			}
43			if v, ok := strings.CutPrefix(l, "priority:"); ok {
44				priorityLabel = strings.TrimSpace(v)
45			}
46		}
47	
48		// Priority drives the floor: critical/high work gets smart, low/trivial
49		// is happy at cheap. Medium falls through to kind- and scope-based logic.
50		switch priorityLabel {
51		case "critical", "urgent":
52			return TierSmart
53		case "high":
54			// High priority bugs/incidents go to smart; high enhancements stay
55			// at standard so we don't burn smart-tier budget on routine work.
56			if isBugKind(kindLabel) || isBugKind(b.IssueType) {
57				return TierSmart
58			}
59			return TierStandard
60		case "low", "trivial":
61			return TierCheap
62		}
63	
64		kind := kindLabel
65		if kind == "" {
66			kind = strings.ToLower(strings.TrimSpace(b.IssueType))
67		}
68		switch {
69		case isBugKind(kind):
70			return TierStandard
71		case isCheapKind(kind):
72			return TierCheap
73		case isStandardKind(kind):
74			return TierStandard
75		}
76	
77		// Estimated scope from description length. Long, dense descriptions tend
78		// to indicate larger work; short descriptions are typically mechanical.
79		descLen := len(b.Description) + len(b.Acceptance)
80		switch {
81		case descLen >= 4000:
82			return TierSmart
83		case descLen >= 1500:
84			return TierStandard
85		default:
86			return TierCheap
87		}
88	}
89	
90	func triageTierHint(b *bead.Bead) (ModelTier, bool) {
91		if b == nil || b.Extra == nil {
92			return "", false
93		}
94		raw, ok := b.Extra[triageTierHintKey]
95		if !ok {
96			return "", false
97		}
98		return parseTierValue(fmt.Sprint(raw))
99	}
100	
101	func parseTierValue(raw string) (ModelTier, bool) {
102		l := strings.ToLower(strings.TrimSpace(raw))
103		if l == "" {
104			return "", false
105		}
106		if strings.HasPrefix(l, "tier:") {
107			return parseTierLabel(l)
108		}
109		switch l {
110		case string(TierSmart):
111			return TierSmart, true
112		case string(TierStandard):
113			return TierStandard, true
114		case string(TierCheap):
115			return TierCheap, true
116		default:
117			return "", false
118		}
119	}
120	
121	func isBugKind(s string) bool {
122		switch strings.ToLower(strings.TrimSpace(s)) {
123		case "bug", "fix", "incident", "regression", "defect":
124			return true
125		}
126		return false
127	}
128	
129	func isCheapKind(s string) bool {
130		switch strings.ToLower(strings.TrimSpace(s)) {
131		case "chore", "docs", "doc", "documentation", "cleanup", "typo", "rename":
132			return true
133		}
134		return false
135	}
136	
137	func isStandardKind(s string) bool {
138		switch strings.ToLower(strings.TrimSpace(s)) {
139		case "enhancement", "feature", "story", "task", "refactor", "test":
140			return true
141		}
142		return false
143	}
