23	func (s *implementationProfileSelector) Select(ctx context.Context, tier escalation.ModelTier, floor int) (agent.ImplementationProfileSelection, error) {
24		if s == nil {
25			return agent.ImplementationProfileSelection{}, nil
26		}
27		s.once.Do(func() {
28			svc, err := agent.ResolveServiceFromWorkDir(s.projectRoot)
