194		pt := rcfg.Passthrough()
195	
196		harness := runtime.HarnessOverride
197		if harness == "" && !runtime.ClearRoutingPins {
198			harness = pt.Harness
199		}
200	
201		model := runtime.ModelOverride
202		if model == "" && !runtime.ClearRoutingPins {
203			model = pt.Model
204		}
205	
206		provider := runtime.ProviderOverride
207		if provider == "" && !runtime.ClearRoutingPins {
208			provider = pt.Provider
209		}
210		if runtime.ClearRoutingPins && runtime.ProviderOverride == "" {
211			provider = ""
212		}
213	
214		profile := runtime.ProfileOverride
215		if profile == "" && !runtime.ClearProfile {
216			profile = rcfg.Profile()
217		}
218	
219		permissions := runtime.PermissionsOverride
220		if permissions == "" {
221			permissions = rcfg.Permissions()
222		}
223	
224		providerTimeout := ResolveProviderRequestTimeout(workDir, provider, model, rcfg.ProviderRequestTimeout())
225	
226		minPower := rcfg.MinPower()
227		if runtime.MinPowerOverride > 0 {
228			minPower = runtime.MinPowerOverride
229		}
230		if runtime.ClearMinPower {
231			minPower = 0
232		}
233		maxPower := rcfg.MaxPower()
234		if runtime.ClearMaxPower {
235			maxPower = 0
236		}
237		if minPower > 0 && maxPower > 0 && minPower >= maxPower {
238			return nil, fmt.Errorf("agent: invalid power bounds: min_power=%d must be less than max_power=%d", minPower, maxPower)
239		}
240	
241		req := agentlib.ServiceExecuteRequest{
242			Prompt:          promptText,
243			Model:           model,
244			Policy:          profile,
245			Provider:        provider,
246			Harness:         fizeauHarness(harness),
247			Reasoning:       agentlib.Reasoning(rcfg.Effort()),
248			Permissions:     permissions,
249			WorkDir:         wd,
250			Timeout:         wall,
251			IdleTimeout:     idle,
252			ProviderTimeout: providerTimeout,
253			SessionLogDir:   sessionLogDir,
254			Metadata:        metadataWithEnv(runtime.Correlation, runtime.Env),
255			Role:            runtime.Role,
256			CorrelationID:   runtime.CorrelationID,
257			MinPower:        minPower,
258			MaxPower:        maxPower,
259		}
260	
261		cancelCtx, cancel := context.WithCancel(ctx)
262		defer cancel()
263	
264		// When Harness is set and Model is empty, fizeau routes within the harness's
265		// eligible models using Profile/MinPower as the routing constraint. This is the
266		// well-formed request shape for profile-driven dispatch without an explicit model.
267		// fizeau returns ErrHarnessModelIncompatible (typed, non-nil) on pre-dispatch
268		// errors and a failed final event for post-dispatch errors.
269		start := time.Now().UTC()
270		events, err := svc.Execute(cancelCtx, req)
271		if err != nil {
272			return nil, fmt.Errorf("agent: execute: %w", err)
273		}
274	
275		renderer := NewWorkLogRenderer(WorkLogRendererOptions{
276			CurrentBeadID: runtime.Correlation["bead_id"],
277			WorkPhase:     "do",
278		})
279		watchdog := &drainWatchdog{
280			cancel:          cancel,
281			idleTimeout:     idle,
282			toolCallTimeout: time.Duration(ToolCallTimeout) * time.Millisecond,
283		}
284		final, routing, _ := drainServiceEventsWithRenderer(events, runtime.Output, renderer, watchdog)
285		finishedAt := time.Now().UTC()
286		elapsed := finishedAt.Sub(start)
287	
288		result := &Result{
289			Harness:    fizeauHarness(harness),
290			Model:      model,
291			DurationMS: int(elapsed.Milliseconds()),
292		}
293		if routing != nil {
294			result.Provider = routing.Provider
295			if routing.Model != "" {
296				result.Model = routing.Model
297			}
298			if routing.Harness != "" {
299				result.Harness = routing.Harness
300			}
301			if power, speed, cost, source := selectedRoutingCandidateMetrics(routing); power > 0 || speed > 0 || cost > 0 || source != "" {
302				result.PredictedPower = power
303				result.PredictedSpeedTPS = speed
304				result.PredictedCostUSDPer1kTokens = cost
305				result.PredictedCostSource = source
306			}
307		}
308		if final != nil {
309			// Normalized final text from the upstream harness (agent-32e8ff5e);
310			// reviewer verdict extraction now parses this instead of raw stream
311			// frames (ddx-7bc0c8d5).
312			result.Output = final.FinalText
313			if final.Usage != nil {
314				// v0.9.1: Usage fields became *int (nullable).
315				if final.Usage.InputTokens != nil {
316					result.InputTokens = *final.Usage.InputTokens
317				}
318				if final.Usage.OutputTokens != nil {
319					result.OutputTokens = *final.Usage.OutputTokens
320				}
321				if final.Usage.TotalTokens != nil {
322					result.Tokens = *final.Usage.TotalTokens
323				}
324			}
325			if final.CostUSD > 0 {
326				result.CostUSD = final.CostUSD
327			}
328			result.ExitCode = final.ExitCode
329			result.Error = final.Error
330			if final.RoutingActual != nil {
331				if result.Provider == "" {
332					result.Provider = final.RoutingActual.Provider
333				}
334				if final.RoutingActual.Model != "" {
335					result.Model = final.RoutingActual.Model
336				}
337				if final.RoutingActual.Harness != "" {
338					result.Harness = final.RoutingActual.Harness
339				}
340				if final.RoutingActual.Power > 0 {
341					result.ActualPower = final.RoutingActual.Power
342				}
343			}
344			if final.SessionLogPath != "" {
345				result.AgentSessionID = final.SessionLogPath
346			}
347		}
348		result.Error = appendProviderTimeoutHint(result.Error, providerTimeout)
349		normalizeServiceFinalExitCode(result)
350		entry := SessionIndexEntryFromResult(workDir, SessionIndexInputs{
351			Harness:     harness,
352			Model:       model,
353			Provider:    provider,
354			Effort:      rcfg.Effort(),
355			Correlation: runtime.Correlation,
356		}, result, start, finishedAt)
357		_ = AppendSessionIndex(ResolveLogDir(workDir, ""), entry, finishedAt)
358		return result, nil
359	}
