105	func (p *preClaimReadinessChecksPayload) UnmarshalJSON(data []byte) error {
106		trimmed := strings.TrimSpace(string(data))
107		if trimmed == "" || trimmed == "null" {
108			return nil
109		}
110	
111		p.Present = true
112		switch trimmed[0] {
113		case '[':
114			return json.Unmarshal(data, &p.Checks)
115		case '{':
116			var check preClaimReadinessCheck
117			if err := json.Unmarshal(data, &check); err != nil {
118				return err
119			}
120			p.Checks = []preClaimReadinessCheck{check}
121			return nil
122		case '"':
123			var value string
124			if err := json.Unmarshal(data, &value); err != nil {
125				return err
126			}
127			p.Malformed = "readiness_checks must be an object or array"
128			p.Evidence = value
129			return nil
130		default:
131			p.Malformed = "readiness_checks must be an object or array"
132			p.Evidence = trimmed
133			return nil
134		}
135	}
