141	// NewPreClaimIntakeHook constructs the bead-intake complexity gate used
142	// before claim in the work / execute-loop paths. The hook evaluates the bead
143	// using the repository's triage prompt and returns one of the typed intake
144	// outcomes so the loop can decide whether to claim or skip the candidate.
145	//
146	// The hook uses the normal service execution path. Unpinned workers get the
147	// lifecycle hook's strongest-profile hint; explicitly pinned workers keep their
148	// operator route pins. Route failures are infrastructure failures, not
149	// bead-readiness decisions, so they return intake_error and let the loop use
150	// its fail-open readiness path.
151	func NewPreClaimIntakeHook(projectRoot string, store BeadReader, rcfg config.ResolvedConfig, svc agentlib.FizeauService, runner AgentRunner) func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
152		return func(ctx context.Context, beadID string) (PreClaimIntakeResult, error) {
153			if ctx != nil {
154				if err := ctx.Err(); err != nil {
155					return PreClaimIntakeResult{}, err
156				}
157			}
158			if strings.TrimSpace(projectRoot) == "" {
159				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: project root required")
160			}
161			if err := ensureBeadLifecycleSkill(projectRoot); err != nil {
162				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: %w", err)
163			}
164			if store == nil {
165				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: bead reader required")
166			}
167	
168			b, err := store.Get(beadID)
169			if err != nil {
170				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: load bead %s: %w", beadID, err)
171			}
172	
173			prompt, err := buildPreClaimIntakePrompt(projectRoot, store, b)
174			if err != nil {
175				return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: build prompt: %w", err)
176			}
177	
178			runtime := AgentRunRuntime{
179				Prompt:        prompt,
180				WorkDir:       projectRoot,
181				PromptSource:  PreClaimIntakePromptSource,
182				ClearProfile:  true,
183				ClearMinPower: true,
184				ClearMaxPower: true,
185			}
186			applyLifecycleHookRouting(ctx, projectRoot, svc, runner, rcfg, &runtime, SelectStrongestProfile)
187			payload, err := dispatchPreClaimIntakePayload(ctx, projectRoot, svc, runner, rcfg, runtime)
188			if err != nil {
189				return PreClaimIntakeResult{
190					Outcome: PreClaimIntakeError,
191					Detail:  preClaimIntakeRouteUnavailableDetail(err),
192				}, nil
193			}
194	
195			return decodePreClaimIntakePayloadResultWithMode(payload, rcfg.BeadQualityMode())
196		}
197	}
