199	func applyLifecycleHookRouting(ctx context.Context, projectRoot string, svc agentlib.FizeauService, runner AgentRunner, rcfg config.ResolvedConfig, runtime *AgentRunRuntime, selector func(ProfileSnapshot) string) {
200		runtime.ClearRoutingPins = true
201	
202		pinned := false
203		if harness, ok := rcfg.ExplicitHarness(); ok {
204			runtime.HarnessOverride = strings.TrimSpace(harness)
205			pinned = true
206		}
207		if provider, ok := rcfg.ExplicitProvider(); ok {
208			runtime.ProviderOverride = strings.TrimSpace(provider)
209			pinned = true
210		}
211		if model, ok := rcfg.ExplicitModel(); ok {
212			runtime.ModelOverride = strings.TrimSpace(model)
213			pinned = true
214		}
215		if pinned {
216			return
217		}
218		runtime.ProfileOverride = selectProfileForDispatch(ctx, projectRoot, svc, runner, selector)
219	}
