246	func buildPreClaimIntakePrompt(projectRoot string, store BeadReader, b *bead.Bead) (string, error) {
247		env := preClaimIntakePromptEnvelope{
248			Title:         strings.TrimSpace(b.Title),
249			Description:   strings.TrimSpace(b.Description),
250			Acceptance:    strings.TrimSpace(b.Acceptance),
251			Labels:        append([]string(nil), b.Labels...),
252			PriorAttempts: []preClaimIntakeAttempt{},
253			Depth:         beadDecompositionDepth(projectRoot, b),
254			Parent:        strings.TrimSpace(b.Parent),
255			Dependencies:  append([]string(nil), b.DepIDs()...),
256		}
257	
258		// Prior attempts are optional for the gate. If bead history is available,
259		// include the last few attempt/result summaries to help the classifier
260		// distinguish a first-pass atomic bead from repeated decomposition.
261		if store != nil {
262			if eventStore, ok := any(store).(interface {
263				Events(id string) ([]bead.BeadEvent, error)
264			}); ok {
265				if events, err := eventStore.Events(b.ID); err == nil && len(events) > 0 {
266					for i := len(events) - 1; i >= 0 && len(env.PriorAttempts) < 5; i-- {
267						ev := events[i]
268						if ev.Kind != "bead.result" && ev.Kind != "execute-bead" {
269							continue
270						}
271						env.PriorAttempts = append(env.PriorAttempts, preClaimIntakeAttempt{
272							Status:    strings.TrimSpace(ev.Summary),
273							Rationale: strings.TrimSpace(ev.Body),
274						})
275					}
276				}
277			}
278		}
279	
280		body, err := json.MarshalIndent(env, "", "  ")
281		if err != nil {
282			return "", err
283		}
284	
285		var sb strings.Builder
286		sb.WriteString("MODE: intake\n")
287		sb.WriteString("You are evaluating whether this bead is atomic, decomposable, ambiguous, or safely refinable before claim.\n")
288		sb.WriteString("Do not rewrite bead fields in intake mode. If the bead is executable as written, classify it as ready even when the prose could be cleaner.\n")
289		sb.WriteString("Return exactly one JSON object matching the readiness schema with classification, tractability, score, rationale, readiness_checks, suggested_fixes, rewrite, suggested_child_beads, and waivers_applied.\n")
290		sb.WriteString("readiness_checks MUST be a JSON array; it may be empty, and every entry MUST be an object with reason, verdict, evidence, and checkable_before_attempt. It must not be an object or string.\n")
291		sb.WriteString("If the bead is not executable as written but can be made executable by a narrow, semantics-preserving metadata/AC rewrite, emit rewrite with changed_fields, description, and acceptance.\n")
292		sb.WriteString("Put prompt-quality improvements in suggested_fixes only; keep operator_required for actual blockers.\n")
293		sb.WriteString("Preservation rules: non-scope items, governing artifact references (FEAT-NNN, ADR-NNN), named test functions (TestFoo), file:line evidence, and dependency IDs (ddx-XXXXXXXX) must all appear in the replacement description.\n")
294		sb.WriteString("Classify as operator_required only when ambiguity, missing prerequisites, hidden external blockers, or unsafe scope choices prevent an implementation attempt.\n")
295		sb.WriteString("Do not include prose or markdown.\n\n")
296		sb.WriteString("```json\n")
297		sb.Write(body)
298		sb.WriteString("\n```\n")
299		return sb.String(), nil
300	}
