302	func intakeResultPayload(result *Result) (string, error) {
303		if result == nil {
304			return "", fmt.Errorf("pre-claim intake: empty runner result")
305		}
306		text := strings.TrimSpace(result.CondensedOutput)
307		if text == "" {
308			text = strings.TrimSpace(result.Output)
309		}
310		if text == "" {
311			if strings.TrimSpace(result.Error) != "" {
312				return "", fmt.Errorf("pre-claim intake: runner error: %s", strings.TrimSpace(result.Error))
313			}
314			if result.ExitCode != 0 {
315				return "", fmt.Errorf("pre-claim intake: runner exited with code %d and empty output", result.ExitCode)
316			}
317			return "", fmt.Errorf("pre-claim intake: empty output")
318		}
319		candidate, ok := extractJSONCandidate(text)
320		if !ok {
321			return "", fmt.Errorf("pre-claim intake: no JSON object found")
322		}
323		return candidate, nil
324	}
