326	func normalizePreClaimIntakeRewriteFields(fields []string) []string {
327		if len(fields) == 0 {
328			return nil
329		}
330		seen := make(map[string]struct{}, len(fields))
331		out := make([]string, 0, len(fields))
332		for _, field := range fields {
333			field = strings.ToLower(strings.TrimSpace(field))
334			if field == "" {
335				continue
336			}
337			if _, ok := seen[field]; ok {
338				continue
339			}
340			seen[field] = struct{}{}
341			out = append(out, field)
342		}
343		return out
344	}
