353	func decodePreClaimIntakePayloadResultWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
354		var probe struct {
355			Classification  string                         `json:"classification"`
356			Outcome         string                         `json:"outcome"`
357			Tractability    string                         `json:"tractability"`
358			Rationale       string                         `json:"rationale"`
359			Score           *int                           `json:"score"`
360			ReadinessChecks preClaimReadinessChecksPayload `json:"readiness_checks"`
361			SuggestedFixes  []struct {
362				Target string `json:"target,omitempty"`
363			} `json:"suggested_fixes"`
364		}
365		if err := json.Unmarshal([]byte(payload), &probe); err != nil {
366			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
367		}
368		if probe.Outcome != "" {
369			return decodeCanonicalReadinessPayloadWithMode(payload, qualityMode)
370		}
371		if probe.Classification != "" {
372			if isReadinessClassificationPayload(probe.Classification, probe.Tractability, probe.Rationale, probe.Score, probe.ReadinessChecks.Present, probe.ReadinessChecks.Len(), len(probe.SuggestedFixes)) {
373				return decodeReadinessClassificationPayloadWithMode(payload, qualityMode)
374			}
375			return decodeLegacyIntakePayload(payload)
376		}
377		return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification or outcome field")
378	}
