380	func isReadinessClassificationPayload(classification, tractability, rationale string, score *int, readinessChecksPresent bool, checkCount, fixCount int) bool {
381		switch strings.ToLower(strings.TrimSpace(classification)) {
382		case ReadinessClassificationSystemUnready,
383			"readiness_error",
384			"intake_error",
385			ReadinessClassificationNeedsRefine,
386			ReadinessClassificationNeedsSplit,
387			ReadinessClassificationOperatorRequired:
388			return true
389		case "ready":
390			return readinessChecksPresent ||
391				strings.TrimSpace(tractability) != "" ||
392				strings.TrimSpace(rationale) != "" ||
393				score != nil ||
394				checkCount > 0 ||
395				fixCount > 0
396		default:
397			return false
398		}
399	}
