401	func decodeCanonicalReadinessPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
402		var out preClaimReadinessPromptResult
403		if err := json.Unmarshal([]byte(payload), &out); err != nil {
404			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness result: %w", err)
405		}
406		detail := strings.TrimSpace(out.Reason)
407		if detail == "" {
408			detail = strings.TrimSpace(out.Detail)
409		}
410		rewrite := PreClaimIntakeRewrite{
411			Description:   strings.TrimSpace(out.Rewrite.Description),
412			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
413			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
414		}
415		switch strings.ToLower(strings.TrimSpace(out.Outcome)) {
416		case "actionable_atomic":
417			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: detail}, nil
418		case "actionable_but_rewritten":
419			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableButRewritten, Detail: detail, Rewrite: rewrite}, nil
420		case "too_large_decomposed":
421			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Reason: ReadinessReasonTooLarge, Detail: detail}, nil
422		case "operator_required", "human_review_required":
423			return PreClaimIntakeResult{Outcome: PreClaimIntakeOperatorRequired, Reason: ReadinessReasonAmbiguousScope, Detail: detail}, nil
424		case "ambiguous_needs_human", "needs_human":
425			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy readiness outcome %q removed by lifecycle migration; use %q", out.Outcome, PreClaimIntakeOperatorRequired)
426		case "readiness_error", "system_unready":
427			// system_unready maps to fail-open/skip per ADR-023/FEAT-010 policy
428			classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
429			return PreClaimIntakeResult{
430				Outcome:      PreClaimIntakeError,
431				Reason:       classified.Reason,
432				SystemReason: classified.SystemReason,
433				Detail:       detail,
434			}, nil
435		case "":
436			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing outcome")
437		default:
438			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: unknown readiness outcome %q: expected one of actionable_atomic, actionable_but_rewritten, too_large_decomposed, operator_required, readiness_error, system_unready", out.Outcome)
439		}
440	}
441	
442	func decodeReadinessClassificationPayloadWithMode(payload string, qualityMode string) (PreClaimIntakeResult, error) {
443		var out preClaimReadinessClassificationPromptResult
444		if err := json.Unmarshal([]byte(payload), &out); err != nil {
445			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode readiness classification result: %w", err)
446		}
447		if out.ReadinessChecks.Malformed != "" {
448			detail := malformedReadinessChecksDetail(out.ReadinessChecks)
449			classified := ClassifyReadinessWithMode(ReadinessClassificationSystemUnready, nil, detail, qualityMode)
450			return PreClaimIntakeResult{
451				Outcome:      classified.IntakeOutcome,
452				Reason:       classified.Reason,
453				SystemReason: classified.SystemReason,
454				Detail:       detail,
455			}, nil
456		}
457		reasons := failedReadinessReasons(out.ReadinessChecks.Checks)
458		detail := firstNonEmptyReadinessDetail(out.Rationale, out.Detail, out.Reasoning)
459		classified := ClassifyReadinessWithMode(out.Classification, reasons, detail, qualityMode)
460		if detail == "" {
461			detail = readinessCheckEvidence(out.ReadinessChecks.Checks)
462		}
463		detail = readinessDetailWithReason(classified, detail)
464	
465		rewrite := PreClaimIntakeRewrite{
466			Description:   strings.TrimSpace(out.Rewrite.Description),
467			Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
468			ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
469		}
470		result := PreClaimIntakeResult{
471			Outcome:      classified.IntakeOutcome,
472			Reason:       classified.Reason,
473			SystemReason: classified.SystemReason,
474			Detail:       detail,
475		}
476		if classified.Classification == ReadinessClassificationNeedsRefine && hasPreClaimIntakeRewrite(rewrite) {
477			result.Outcome = PreClaimIntakeActionableButRewritten
478			result.Rewrite = rewrite
479		}
480		return result, nil
481	}
482	
483	func failedReadinessReasons(checks []preClaimReadinessCheck) []string {
484		reasons := make([]string, 0, len(checks))
485		for _, check := range checks {
486			verdict := strings.ToLower(strings.TrimSpace(check.Verdict))
487			if verdict != "fail" {
488				continue
489			}
490			if reason := strings.TrimSpace(check.Reason); reason != "" {
491				reasons = append(reasons, reason)
492			}
493		}
494		return reasons
495	}
496	
497	func malformedReadinessChecksDetail(checks preClaimReadinessChecksPayload) string {
498		detail := strings.TrimSpace(checks.Malformed)
499		if detail == "" {
500			detail = "readiness_checks must be an object or array"
501		}
502		if evidence := strings.TrimSpace(checks.Evidence); evidence != "" {
503			detail += ": " + strconv.Quote(evidence)
504		}
505		return detail
506	}
507	
508	func readinessCheckEvidence(checks []preClaimReadinessCheck) string {
509		for _, check := range checks {
510			if strings.ToLower(strings.TrimSpace(check.Verdict)) != "fail" {
511				continue
512			}
513			if evidence := strings.TrimSpace(check.Evidence); evidence != "" {
514				return evidence
515			}
516		}
517		return ""
518	}
519	
520	func readinessDetailWithReason(classified ReadinessClassificationResult, detail string) string {
521		detail = strings.TrimSpace(detail)
522		reason := strings.TrimSpace(classified.Reason)
523		if reason == "" {
524			return detail
525		}
526		if detail == "" {
527			return reason
528		}
529		if strings.Contains(strings.ToLower(detail), strings.ToLower(reason)) {
530			return detail
531		}
532		return reason + ": " + detail
533	}
534	
535	func firstNonEmptyReadinessDetail(values ...string) string {
536		for _, value := range values {
537			if trimmed := strings.TrimSpace(value); trimmed != "" {
538				return trimmed
539			}
540		}
541		return ""
542	}
543	
544	func hasPreClaimIntakeRewrite(rewrite PreClaimIntakeRewrite) bool {
545		return strings.TrimSpace(rewrite.Description) != "" ||
546			strings.TrimSpace(rewrite.Acceptance) != "" ||
547			len(rewrite.ChangedFields) > 0
548	}
549	
550	func decodeLegacyIntakePayload(payload string) (PreClaimIntakeResult, error) {
551		var out preClaimIntakePromptResult
552		if err := json.Unmarshal([]byte(payload), &out); err != nil {
553			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: decode result: %w", err)
554		}
555		switch strings.ToLower(strings.TrimSpace(out.Classification)) {
556		case "atomic", "ok", "ready", "actionable", "pass":
557			return PreClaimIntakeResult{Outcome: PreClaimIntakeActionableAtomic, Detail: strings.TrimSpace(out.Reasoning)}, nil
558		case "rewritten":
559			return PreClaimIntakeResult{
560				Outcome: PreClaimIntakeActionableButRewritten,
561				Detail:  strings.TrimSpace(out.Reasoning),
562				Rewrite: PreClaimIntakeRewrite{
563					Description:   strings.TrimSpace(out.Rewrite.Description),
564					Acceptance:    strings.TrimSpace(out.Rewrite.Acceptance),
565					ChangedFields: normalizePreClaimIntakeRewriteFields(out.Rewrite.ChangedFields),
566				},
567			}, nil
568		case "decomposable":
569			return PreClaimIntakeResult{Outcome: PreClaimIntakeTooLargeDecomposed, Detail: strings.TrimSpace(out.Reasoning)}, nil
570		case "ambiguous", "ambiguous_scope", "needs_human", "ambiguous_needs_human":
571			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: legacy classification %q removed by lifecycle migration; use outcome %q", out.Classification, PreClaimIntakeOperatorRequired)
572		case "":
573			return PreClaimIntakeResult{}, fmt.Errorf("pre-claim intake: missing classification")
574		default:
575			return PreClaimIntakeResult{}, fmt.Errorf(
576				"pre-claim intake: unknown classification %q: expected one of ready, needs_refine, needs_split, operator_required, system_unready",
577				out.Classification,
578			)
579		}
580	}
