	lastReq := requests[0]
	// AC1: no-flag ddx work sends no harness/model/provider pins.
	assert.Empty(t, lastReq.Harness, "endpoint-only work must not hard-pin a harness")
	assert.Empty(t, lastReq.Provider, "endpoint-only work must not hard-pin a provider")
	assert.Empty(t, lastReq.Model, "endpoint-only work must not hard-pin a model")
	// Core regression: a non-empty Policy must be selected from the live Fizeau
	// snapshot. If projectHasRoutingConfig is over-broad, this is "" and Fizeau
	// falls back to its default policy (the production failure mode).
	assert.NotEmpty(t, lastReq.Policy,
		"endpoint-only work must select a routing policy by metadata, not delegate to Fizeau's default")
	assert.Equal(t, 0, lastReq.MinPower, "initial endpoint-only dispatch must not duplicate the selected policy floor as MinPower")
}

