// whose Prompt begins with the given prefix. Used by ddx-e0b95b4a routing tests
// to separate readiness/intake dispatches (PromptSource "bead-lifecycle-intake",
// prompt prefix "MODE: intake") from implementation dispatches in a single
// `ddx work --once` run.
func capturedRequestsByPromptPrefix(stub *executeCapturingStub, prefix string) []agentlib.ServiceExecuteRequest {
	stub.mu.Lock()
	defer stub.mu.Unlock()
	out := make([]agentlib.ServiceExecuteRequest, 0, len(stub.requests))
	for _, req := range stub.requests {
		if strings.HasPrefix(req.Prompt, prefix) {
			out = append(out, req)
		}
	}
	return out
}

