// TestProjectHasRoutingConfig_EndpointsAreTransportNotRoutingPin covers
// ddx-e0b95b4a. agent.endpoints declares where providers live (transport
// config) — it does NOT pin a routing decision the way agent.model does.
// Treating endpoints as a routing pin disables zero-config tier inference and
// causes no-flag `ddx work` to send an empty Policy, which Fizeau then
// resolves via its default policy (in production this scored Opus on ordinary
// implementation work — see ddx-e0b95b4a/events.jsonl for two captured runs
// at $15.08 and $6.83).
//
// The matrix verifies the new contract: only an explicit model pin in
// agent.config.yaml suppresses zero-config tier inference; endpoints, an empty
// agent block, or no config at all leave inference active.
func TestProjectHasRoutingConfig_EndpointsAreTransportNotRoutingPin(t *testing.T) {
	cases := []struct {
		name     string
		writeCfg bool
		yaml     string
		want     bool
	}{
		{
			name:     "no .ddx/config.yaml",
			writeCfg: false,
			want:     false,
		},
		{
			name:     "library-only config (zero-config baseline)",
			writeCfg: true,
			yaml: `version: "1.0"
library:
  path: ".ddx/plugins/ddx"
  repository:
    url: "https://example.com/lib"
    branch: "main"
`,
			want: false,
		},
		{
			name:     "endpoints only, no model pin (production scenario)",
			writeCfg: true,
			yaml: `version: "1.0"
library:
  path: ".ddx/plugins/ddx"
