// TestWorkEndpointOnlyConfigStillInfersImplementationPolicy covers ddx-e0b95b4a:
// when .ddx/config.yaml declares agent.endpoints (transport config) but no model
// pin, no-flag `ddx work` must still treat the project as zero-config for routing
// and let the implementation profile selector pick a Fizeau policy. The
// regression was projectHasRoutingConfig returning true on endpoints alone,
// which suppressed tier inference and sent an empty Policy — Fizeau then
// inherited its default policy and scored a high-power model (Opus in
// production) for ordinary implementation work.
func TestWorkEndpointOnlyConfigStillInfersImplementationPolicy(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
	stub := installExecuteCapturingStub(t)
	stub.listPolicies, stub.listModels = canonicalFizeauPolicyFixture()
	stub.executeFn = func(req agentlib.ServiceExecuteRequest) (<-chan agentlib.ServiceEvent, error) {
		ch := make(chan agentlib.ServiceEvent, 1)
		ch <- agentlib.ServiceEvent{Type: "final", Data: []byte(`{"status":"success","final_text":"{\"classification\":\"ready\",\"rationale\":\"ok\",\"readiness_checks\":[],\"score\":9,\"suggested_fixes\":[],\"waivers_applied\":[],\"recommended_action\":\"release_claim_retry\",\"suggested_amendments\":[],\"suggested_followup_beads\":[]}"}`)}
		close(ch)
		return ch, nil
	}

	dir := minimalProjectDir(t)
	// Overwrite the minimal config with one that adds agent.endpoints but no
	// model pin — the production scenario where the bug fired.
	endpointCfg := `version: "1.0"
library:
  path: ".ddx/plugins/ddx"
  repository:
    url: "https://example.com/lib"
    branch: "main"
agent:
  endpoints:
    - type: lmstudio
      host: 127.0.0.1
      port: 1234
`
	require.NoError(t, os.WriteFile(filepath.Join(dir, ".ddx", "config.yaml"), []byte(endpointCfg), 0o644))

	require.NoError(t, os.WriteFile(filepath.Join(dir, "README.md"), []byte("# test\n"), 0o644))
	require.NoError(t, exec.Command("git", "init", dir).Run())
	require.NoError(t, exec.Command("git", "-C", dir, "config", "user.email", "test@example.com").Run())
	require.NoError(t, exec.Command("git", "-C", dir, "config", "user.name", "Test User").Run())
	require.NoError(t, exec.Command("git", "-C", dir, "add", ".").Run())
	require.NoError(t, exec.Command("git", "-C", dir, "commit", "-m", "init").Run())
	store := bead.NewStore(filepath.Join(dir, ".ddx"))
	require.NoError(t, store.Init())
	require.NoError(t, store.Create(&bead.Bead{
		ID:        "ddx-endpoint-only-routing",
		Title:     "Work in endpoint-only config selects implementation policy",
		IssueType: "bug",
	}))

	factory := NewCommandFactory(dir)
	root := factory.NewRootCommand()
	out, err := executeCommand(
		root,
		"work",
		"--once",
		"--project", dir,
		"--no-review",
		"--no-review-i-know-what-im-doing",
	)

	requests := capturedImplementationRequests(stub)
	require.NotEmpty(t, requests, "ddx work must invoke implementation dispatch; output=%q err=%v", out, err)
	lastReq := requests[0]
	// AC1: no-flag ddx work sends no harness/model/provider pins.
	assert.Empty(t, lastReq.Harness, "endpoint-only work must not hard-pin a harness")
	assert.Empty(t, lastReq.Provider, "endpoint-only work must not hard-pin a provider")
	assert.Empty(t, lastReq.Model, "endpoint-only work must not hard-pin a model")
	// Core regression: a non-empty Policy must be selected from the live Fizeau
	// snapshot. If projectHasRoutingConfig is over-broad, this is "" and Fizeau
	// falls back to its default policy (the production failure mode).
	assert.NotEmpty(t, lastReq.Policy,
		"endpoint-only work must select a routing policy by metadata, not delegate to Fizeau's default")
	assert.Equal(t, 0, lastReq.MinPower, "initial endpoint-only dispatch must not duplicate the selected policy floor as MinPower")

	// AC2: readiness/intake routing is captured separately so an operator can
	// diagnose expensive readiness defaults independently of implementation
	// routing. Intake requests are unpinned but use the strongest profile by
	// design (see NewPreClaimIntakeHook); this assertion records that contract
	// so future changes to lifecycle-hook routing are visible.
	intakeReqs := capturedRequestsByPromptPrefix(stub, "MODE: intake")
	require.NotEmpty(t, intakeReqs, "ddx work must invoke readiness/intake dispatch; output=%q err=%v", out, err)
	intakeReq := intakeReqs[0]
	assert.Empty(t, intakeReq.Harness, "readiness/intake dispatch must not hard-pin a harness")
	assert.Empty(t, intakeReq.Provider, "readiness/intake dispatch must not hard-pin a provider")
	assert.Empty(t, intakeReq.Model, "readiness/intake dispatch must not hard-pin a model")
	assert.NotEmpty(t, intakeReq.Policy,
		"readiness/intake dispatch must select a routing policy by metadata, not delegate to Fizeau's default")
}

// capturedRequestsByPromptPrefix returns captured executeCapturingStub requests
// whose Prompt begins with the given prefix. Used by ddx-e0b95b4a routing tests
// to separate readiness/intake dispatches (PromptSource "bead-lifecycle-intake",
// prompt prefix "MODE: intake") from implementation dispatches in a single
// `ddx work --once` run.
func capturedRequestsByPromptPrefix(stub *executeCapturingStub, prefix string) []agentlib.ServiceExecuteRequest {
	stub.mu.Lock()
	defer stub.mu.Unlock()
	out := make([]agentlib.ServiceExecuteRequest, 0, len(stub.requests))
	for _, req := range stub.requests {
		if strings.HasPrefix(req.Prompt, prefix) {
			out = append(out, req)
		}
	}
	return out
}

